  1→//! Per-function fingerprinting for staleness detection.
  2→//!
  3→//! A fingerprint is a stable SHA-256 hash of a function's source text,
  4→//! parameter types, and branch structure. When a fingerprint matches a
  5→//! previously cached value, the function is unchanged and can be skipped
  6→//! during re-exploration.
  7→
  8→use std::collections::{HashMap, HashSet};
  9→use std::fmt::Write as _;
 10→use std::path::Path;
 11→
 12→use sha2::{Digest, Sha256};
 13→
 14→use crate::protocol::FunctionAnalysis;
 15→
 16→/// Compute a hex-encoded SHA-256 fingerprint for a function.
 17→///
 18→/// The fingerprint incorporates:
 19→/// - The function's source text (verbatim, including whitespace)
 20→/// - Parameter names and types (sorted by name for stability)
 21→/// - Branch structure: IDs, lines, condition text, types (sorted by ID)
 22→///
 23→/// Any change to these inputs produces a different fingerprint.
 24→pub fn compute_function_fingerprint(source_text: &str, analysis: &FunctionAnalysis) -> String {
 25→    let mut hasher = Sha256::new();
 26→
 27→    // Hash source text.
 28→    hasher.update(b"source:");
 29→    hasher.update(source_text.as_bytes());
 30→
 31→    // Hash parameters (sorted by name for determinism).
 32→    let mut params: Vec<_> = analysis
 33→        .params
 34→        .iter()
 35→        .map(|p| {
 36→            let mut s = String::new();
 37→            let _ = write!(s, "{}:{:?}", p.name, p.typ);
 38→            if let Some(ref tn) = p.type_name {
 39→                let _ = write!(s, "/{tn}");
 40→            }
 41→            s
 42→        })
 43→        .collect();
 44→    params.sort();
 45→
 46→    hasher.update(b"params:");
 47→    for p in &params {
 48→        hasher.update(p.as_bytes());
 49→        hasher.update(b"\n");
 50→    }
 51→
 52→    // Hash branch structure (sorted by branch ID for determinism).
 53→    let mut branches: Vec<_> = analysis
 54→        .branches
 55→        .iter()
 56→        .map(|b| {
 57→            let mut s = String::new();
 58→            let _ = write!(s, "{}:{}:{:?}:{}", b.id, b.line, b.branch_type, b.condition_text);
 59→            s
 60→        })
 61→        .collect();
 62→    branches.sort();
 63→
 64→    hasher.update(b"branches:");
 65→    for b in &branches {
 66→        hasher.update(b.as_bytes());
 67→        hasher.update(b"\n");
 68→    }
 69→
 70→    format!("{:x}", hasher.finalize())
 71→}
 72→
 73→/// Compute a deep fingerprint that incorporates callee fingerprints.
 74→///
 75→/// Extends the shallow fingerprint by hashing in the deep fingerprints of all
 76→/// in-scope callees (sorted by name for determinism). Callees not present in
 77→/// `callee_deep_fingerprints` are ignored (they are out-of-scope and assumed stable).
 78→///
 79→/// Because scans process functions leaves-first, callee deep fingerprints are
 80→/// always available before the caller is processed.
 81→pub fn compute_deep_fingerprint(
 82→    shallow_fingerprint: &str,
 83→    callee_deep_fingerprints: &HashMap<String, String>,
 84→    callees: &HashSet<String>,
 85→) -> String {
 86→    let mut hasher = Sha256::new();
 87→    hasher.update(b"shallow:");
 88→    hasher.update(shallow_fingerprint.as_bytes());
 89→
 90→    let mut callee_fps: Vec<(&str, &str)> = callees
 91→        .iter()
 92→        .filter_map(|c| {
 93→            callee_deep_fingerprints
 94→                .get(c)
 95→                .map(|fp| (c.as_str(), fp.as_str()))
 96→        })
 97→        .collect();
 98→    callee_fps.sort_by_key(|(name, _)| *name);
 99→
100→    hasher.update(b"callees:");
101→    for (name, fp) in &callee_fps {
102→        hasher.update(name.as_bytes());
103→        hasher.update(b"=");
104→        hasher.update(fp.as_bytes());
105→        hasher.update(b"\n");
106→    }
107→
108→    format!("{:x}", hasher.finalize())
109→}
