111→/// Compute deep fingerprints for all functions in a single file.
112→///
113→/// For each analysis, computes a shallow fingerprint from source text + metadata,
114→/// then composes it with callee deep fingerprints. Functions are processed in
115→/// dependency order (leaves first via Kahn's algorithm on out-edges) so callee
116→/// fingerprints are available when computing callers. Out-of-scope callees
117→/// (not in `analyses`) are ignored. Cycles are broken by processing remaining
118→/// functions with partial callee fingerprints.
119→///
120→/// Returns a map from function name to deep fingerprint.
121→pub fn compute_deep_fingerprints(
122→    file_path: &Path,
123→    analyses: &[FunctionAnalysis],
124→) -> Result<HashMap<String, String>, std::io::Error> {
125→    let name_set: HashSet<&str> = analyses.iter().map(|a| a.name.as_str()).collect();
126→
127→    // Compute shallow fingerprints for all functions.
128→    let mut shallow: HashMap<String, String> = HashMap::new();
129→    for func in analyses {
130→        let source = extract_function_source(file_path, func.start_line, func.end_line)?;
131→        shallow.insert(func.name.clone(), compute_function_fingerprint(&source, func));
132→    }
133→
134→    // Build in-scope callee sets per function.
135→    let callees_map: HashMap<&str, HashSet<String>> = analyses
136→        .iter()
137→        .map(|func| {
138→            let callees: HashSet<String> = func
139→                .dependencies
140→                .iter()
141→                .map(|d| d.symbol.clone())
142→                .filter(|s| name_set.contains(s.as_str()))
143→                .collect();
144→            (func.name.as_str(), callees)
145→        })
146→        .collect();
147→
148→    // Kahn's algorithm: process leaves (no in-scope callees) first.
149→    // out_degree = number of unprocessed in-scope callees.
150→    let mut out_degree: HashMap<&str, usize> = analyses
151→        .iter()
152→        .map(|f| {
153→            (
154→                f.name.as_str(),
155→                callees_map.get(f.name.as_str()).map_or(0, HashSet::len),
156→            )
157→        })
158→        .collect();
159→
160→    // Reverse: callee → list of callers.
161→    let mut reverse: HashMap<&str, Vec<&str>> = HashMap::new();
162→    for (&caller, callees) in &callees_map {
163→        for callee in callees {
164→            reverse.entry(callee.as_str()).or_default().push(caller);
165→        }
166→    }
167→
168→    let mut queue: Vec<&str> = out_degree
169→        .iter()
170→        .filter(|(_, deg)| **deg == 0)
171→        .map(|(&name, _)| name)
172→        .collect();
173→    queue.sort();
174→
175→    let mut deep: HashMap<String, String> = HashMap::new();
176→
177→    while let Some(func_name) = queue.pop() {
178→        if let Some(sfp) = shallow.get(func_name) {
179→            let callees = callees_map
180→                .get(func_name)
181→                .cloned()
182→                .unwrap_or_default();
183→            deep.insert(
184→                func_name.to_string(),
185→                compute_deep_fingerprint(sfp, &deep, &callees),
186→            );
187→        }
188→
189→        if let Some(callers) = reverse.get(func_name) {
190→            for &caller in callers {
191→                if let Some(deg) = out_degree.get_mut(caller) {
192→                    *deg = deg.saturating_sub(1);
193→                    if *deg == 0 {
194→                        queue.push(caller);
195→                        queue.sort();
196→                    }
197→                }
198→            }
199→        }
200→    }
201→
202→    // Cycle remnants: process with partial callee fingerprints.
203→    for func in analyses {
204→        if !deep.contains_key(&func.name)
205→            && let Some(sfp) = shallow.get(&func.name)
206→        {
207→            let callees = callees_map
208→                .get(func.name.as_str())
209→                .cloned()
210→                .unwrap_or_default();
211→            deep.insert(
212→                func.name.clone(),
213→                compute_deep_fingerprint(sfp, &deep, &callees),
214→            );
215→        }
216→    }
217→
218→    Ok(deep)
219→}
